insert into public.chat_messages (
  id, thread_id, sender_id, message_type, body, sent_at_label, sort_order, created_at
) values
('00000000-0000-0000-0000-000000005001','00000000-0000-0000-0000-000000004001','00000000-0000-0000-0000-000000001000','buyer','안녕하세요 혹시 아직 있을까요? 실사용하시던 거면 상태가 어느 정도인지 궁금해요.','오전 10:01',0,'2026-04-14T10:01:00+09:00'::timestamptz),
('00000000-0000-0000-0000-000000005002','00000000-0000-0000-0000-000000004001','00000000-0000-0000-0000-000000001001','seller','네 있어요. 배터리 효율 87%고 테두리에 생활기스는 조금 있는데, 화면이랑 카메라는 깔끔한 편이에요.','오전 10:03',1,'2026-04-14T10:03:00+09:00'::timestamptz),
('00000000-0000-0000-0000-000000005003','00000000-0000-0000-0000-000000004001','00000000-0000-0000-0000-000000001000','buyer','아 그 정도면 괜찮네요. 가격도 보고 연락드린 건데 41만원까지는 어려우실까요?','오전 10:06',2,'2026-04-14T10:06:00+09:00'::timestamptz),
('00000000-0000-0000-0000-000000005004','00000000-0000-0000-0000-000000004001','00000000-0000-0000-0000-000000001001','seller','41만원은 조금 어렵고요, 많이 말고 조금은 조정 가능해요.','오전 10:07',3,'2026-04-14T10:07:00+09:00'::timestamptz),
('00000000-0000-0000-0000-000000005005','00000000-0000-0000-0000-000000004001','00000000-0000-0000-0000-000000001000','buyer','그러면 42만원이면 괜찮을 것 같아요. 내일 저녁에 합정역 근처 가능하실까요?','오전 10:08',4,'2026-04-14T10:08:00+09:00'::timestamptz),
('00000000-0000-0000-0000-000000005006','00000000-0000-0000-0000-000000004001','00000000-0000-0000-0000-000000001001','seller','네 가능해요. 그럼 내일 저녁 합정역에서 42만원에 거래하는 걸로 할게요.','오전 10:09',5,'2026-04-14T10:09:00+09:00'::timestamptz),
('00000000-0000-0000-0000-000000005007','00000000-0000-0000-0000-000000004002','00000000-0000-0000-0000-000000001000','buyer','안녕하세요 오늘 올리신 거 보고 바로 연락드렸어요. 아직 안 팔렸죠?','오전 10:11',0,'2026-04-14T10:11:00+09:00'::timestamptz),
('00000000-0000-0000-0000-000000005008','00000000-0000-0000-0000-000000004002','00000000-0000-0000-0000-000000001002','seller','네 아직 있어요. 잔기스는 조금 있는데 심한 찍힘은 없고, 박스도 같이 드릴 수 있어요.','오전 10:13',1,'2026-04-14T10:13:00+09:00'::timestamptz),
('00000000-0000-0000-0000-000000005009','00000000-0000-0000-0000-000000004002','00000000-0000-0000-0000-000000001000','buyer','좋아요. 제가 빠르게 직거래 가능해서 그런데 33만원 정도는 가능하실까요?','오전 10:15',2,'2026-04-14T10:15:00+09:00'::timestamptz),
('00000000-0000-0000-0000-000000005010','00000000-0000-0000-0000-000000004002','00000000-0000-0000-0000-000000001002','seller','33만원까지는 어렵고 34만원이면 가능해요.','오전 10:16',3,'2026-04-14T10:16:00+09:00'::timestamptz),
('00000000-0000-0000-0000-000000005011','00000000-0000-0000-0000-000000004002','00000000-0000-0000-0000-000000001000','buyer','네 그럼 34만원에 할게요. 내일 저녁 망원역 근처에서 가능하실까요?','오전 10:17',4,'2026-04-14T10:17:00+09:00'::timestamptz),
('00000000-0000-0000-0000-000000005012','00000000-0000-0000-0000-000000004002','00000000-0000-0000-0000-000000001002','seller','네 괜찮아요. 내일 저녁에 망원역 근처에서 34만원에 거래하는 걸로 하죠.','오전 10:18',5,'2026-04-14T10:18:00+09:00'::timestamptz),
('00000000-0000-0000-0000-000000005013','00000000-0000-0000-0000-000000004003','00000000-0000-0000-0000-000000001000','buyer','안녕하세요 사진이 깔끔해서 연락드려요. 아직 거래 가능할까요?','오전 10:21',0,'2026-04-14T10:21:00+09:00'::timestamptz),
('00000000-0000-0000-0000-000000005014','00000000-0000-0000-0000-000000004003','00000000-0000-0000-0000-000000001003','seller','네 가능해요. 기기 상태는 괜찮고, 펜슬은 없어요. 아이패드 본체랑 케이스만 같이 드려요.','오전 10:23',1,'2026-04-14T10:23:00+09:00'::timestamptz),
('00000000-0000-0000-0000-000000005015','00000000-0000-0000-0000-000000004003','00000000-0000-0000-0000-000000001000','buyer','아 확인했습니다. 혹시 가격은 49만원 정도로 맞춰주실 수 있을까요?','오전 10:25',2,'2026-04-14T10:25:00+09:00'::timestamptz),
('00000000-0000-0000-0000-000000005016','00000000-0000-0000-0000-000000004003','00000000-0000-0000-0000-000000001003','seller','49만원은 조금 아쉽고 50만원까지는 가능해요.','오전 10:26',3,'2026-04-14T10:26:00+09:00'::timestamptz),
('00000000-0000-0000-0000-000000005017','00000000-0000-0000-0000-000000004003','00000000-0000-0000-0000-000000001000','buyer','네 50이면 괜찮아요. 그럼 내일 저녁에 상수역 근처에서 볼 수 있을까요?','오전 10:27',4,'2026-04-14T10:27:00+09:00'::timestamptz),
('00000000-0000-0000-0000-000000005018','00000000-0000-0000-0000-000000004003','00000000-0000-0000-0000-000000001003','seller','네 가능해요. 내일 저녁 상수역 근처에서 50만원에 거래하는 걸로 할게요.','오전 10:28',5,'2026-04-14T10:28:00+09:00'::timestamptz);

